diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 59e103cda023..65f723e1f235 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -919,6 +919,19 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
     return NewAdd;
   }

+  // add (add (add X, C1), Y), C --> add (add Y, (C1+C)), X
+  // This folds constants through nested adds.
+  const APInt *C1;
+  Value *A, *B;
+  if (match(Op0, m_OneUse(m_Add(m_Add(m_Value(A), m_APInt(C1)), m_Value(B)))))
+    return BinaryOperator::CreateAdd(
+        Builder.CreateAdd(B, ConstantInt::get(Ty, *C1 + *C)), A);
+
+  // add (add (add C1, X), Y), C --> add (add Y, (C1+C)), X
+  if (match(Op0, m_OneUse(m_Add(m_Add(m_APInt(C1), m_Value(A)), m_Value(B)))))
+    return BinaryOperator::CreateAdd(
+        Builder.CreateAdd(B, ConstantInt::get(Ty, *C1 + *C)), A);
+
   // (X | C2) + C --> (X | C2) ^ C2 iff (C2 == -C)
   const APInt *C2;
   if (match(Op0, m_Or(m_Value(), m_APInt(C2))) && *C2 == -*C)
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 60da48e1d95d..786d5f01922f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7471,6 +7471,64 @@ Instruction *InstCombinerImpl::foldICmpCommutative(CmpPredicate Pred,
     if (Instruction *Res = foldICmpWithMinMax(CxtI, MinMax, Op1, Pred))
       return Res;

+  // icmp eq/ne X, clamp(X, Lo, Hi) --> icmp ule/ugt (X-Lo), (Hi-Lo)
+  // clamp is smin(smax(X, Lo), Hi) or smax(smin(X, Hi), Lo)
+  // or the unsigned equivalents.
+  if (CxtI.isEquality()) {
+    Value *X;
+    const APInt *Lo = nullptr, *Hi = nullptr;
+    bool IsSigned = false, Matched = false;
+    auto MatchSMinSMax = [&]() {
+      return match(Op0, m_Intrinsic<Intrinsic::smin>(
+                            m_Intrinsic<Intrinsic::smax>(m_Value(X), m_APInt(Lo)),
+                            m_APInt(Hi))) &&
+             Op1 == X;
+    };
+    auto MatchSMaxSMin = [&]() {
+      return match(Op0, m_Intrinsic<Intrinsic::smax>(
+                            m_Intrinsic<Intrinsic::smin>(m_Value(X), m_APInt(Hi)),
+                            m_APInt(Lo))) &&
+             Op1 == X;
+    };
+    auto MatchUMinUMax = [&]() {
+      return match(Op0, m_Intrinsic<Intrinsic::umin>(
+                            m_Intrinsic<Intrinsic::umax>(m_Value(X), m_APInt(Lo)),
+                            m_APInt(Hi))) &&
+             Op1 == X;
+    };
+    auto MatchUMaxUMin = [&]() {
+      return match(Op0, m_Intrinsic<Intrinsic::umax>(
+                            m_Intrinsic<Intrinsic::umin>(m_Value(X), m_APInt(Hi)),
+                            m_APInt(Lo))) &&
+             Op1 == X;
+    };
+    if (MatchSMinSMax() || MatchSMaxSMin()) {
+      IsSigned = true;
+      Matched = true;
+    } else if (MatchUMinUMax() || MatchUMaxUMin()) {
+      IsSigned = false;
+      Matched = true;
+    }
+    if (Matched &&
+        !(IsSigned ? Lo->sgt(*Hi) : Lo->ugt(*Hi))) {
+      // Verify this is a valid clamp: Lo <= Hi
+      // X == clamp(X, Lo, Hi) iff X is in [Lo, Hi]
+      // X != clamp(X, Lo, Hi) iff X is not in [Lo, Hi]
+      // Transform to unsigned range check:
+      // X in [Lo, Hi]  <=>  (X - Lo) <=u (Hi - Lo)
+      // X not in [Lo, Hi] <=> (X - Lo) >u (Hi - Lo)
+      Type *Ty = X->getType();
+      APInt Diff = *Hi - *Lo;
+      Value *Sub = Builder.CreateSub(X, ConstantInt::get(Ty, *Lo));
+      if (Pred == ICmpInst::ICMP_EQ) {
+        return new ICmpInst(ICmpInst::ICMP_ULE, Sub,
+                            ConstantInt::get(Ty, Diff));
+      } else {
+        return new ICmpInst(ICmpInst::ICMP_UGT, Sub,
+                            ConstantInt::get(Ty, Diff));
+      }
+    }
+  }
   {
     Value *X;
     const APInt *C;

